#include <stdio.h>
#include <string.h>
#include <omp.h>

#include "../common.h"
#include "../util/timer/timer.h"
#ifdef TIMING
#include "../../util/timing.h"
#endif

#include "./kernel_gpu_opencl_wrapper.h"

void
kernel_gpu_opencl_wrapper( record *records,
                           long records_mem,
                           knode *knodes,
                           long knodes_elem,
                           long knodes_mem,

                           int order,
                           long maxheight,
                           int count,

                           long *currKnode,
                           long *offset,
                           int *keys,
                           record *ans)
{
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
    gettimeofday(&tv_total_start, NULL);
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_kernel_start, NULL);
#endif

    (void)records_mem;
    (void)knodes_mem;

    size_t local_work_size[1];
    local_work_size[0] = (size_t)(order < 1024 ? order : 1024);
    size_t global_work_size[1];
    global_work_size[0] = (size_t)count * local_work_size[0];

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
           (int)(global_work_size[0] / local_work_size[0]), (int)local_work_size[0]);

    #pragma omp parallel for schedule(static)
    for (int bid = 0; bid < count; bid++) {
        long curr = currKnode[bid];
        long off = offset[bid];

        for (long i = 0; i < maxheight; i++) {
            long next_off = off;

            for (int thid = 0; thid < (int)local_work_size[0]; thid++) {
                if ((knodes[curr].keys[thid] <= keys[bid]) &&
                    (knodes[curr].keys[thid + 1] > keys[bid])) {
                    if (knodes[off].indices[thid] < knodes_elem) {
                        next_off = knodes[off].indices[thid];
                    }
                }
            }

            off = next_off;
            curr = off;
        }

        currKnode[bid] = curr;
        offset[bid] = off;

        for (int thid = 0; thid < (int)local_work_size[0]; thid++) {
            if (knodes[curr].keys[thid] == keys[bid]) {
                ans[bid].value = records[knodes[curr].indices[thid]].value;
            }
        }
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_kernel_end, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    gettimeofday(&tv_close_start, NULL);
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

